sequence.script:
var payload = mc.getPayloadJSON();

if (payload && payload.data && Array.isArray(payload.data)) {

    var cleanedArray = payload.data.map(function(item) {

        if (item && item._id) {
            delete item._id;
        }

        return item;
    });

    mc.setPayloadJSON(cleanedArray);

} else {
    mc.setPayloadJSON([]);
}

var payload = mc.getPayloadJSON();

// ---- Extract from array payload ----
var lossitemsResponse = null;
var policyResponse = null;

for (var i = 0; i < payload.length; i++) {
    if (payload[i].lossitemsResponse) {
        lossitemsResponse = payload[i].lossitemsResponse;
    }
    if (payload[i].policyResponse) {
        policyResponse = payload[i].policyResponse;
    }
}

// ---- Extract first loss item ----
var lossItem = (lossitemsResponse && lossitemsResponse.length > 0)
    ? lossitemsResponse[0]
    : null;

// ---- Parse claimResponse ----
var claimResponseStr = mc.getProperty("claimResponse");
var claimResponse = null;

if (claimResponseStr) {
    try {
        claimResponse = JSON.parse(claimResponseStr);
    } catch (e) {
        print("ERROR parsing claimResponse: " + e);
    }
}

// ---- Handle claimResponse array ----
var claim = null;
if (claimResponse && Array.isArray(claimResponse) && claimResponse.length > 0) {
    claim = claimResponse[0];
}

// ---- Date helper ----
function toDate(d) {
    return d ? new Date(d) : null;
}

// ---- Policy tenure ----
var policyTenureMonths = 0;

if (policyResponse && policyResponse.termStartDate && policyResponse.termEndDate) {
    var startDate = toDate(policyResponse.termStartDate);
    var endDate = toDate(policyResponse.termEndDate);

    policyTenureMonths = (endDate.getFullYear() - startDate.getFullYear()) * 12 +
                         (endDate.getMonth() - startDate.getMonth());
}

// ---- Accident count ----
var accidentCount = 0;

if (claim &&
    claim.policy &&
    claim.policy.driverDetails) {

    accidentCount = claim.policy.driverDetails.accidentCount || 0;
}

// ---- Loss days ----
var lossDays = 0;

if (lossItem && lossItem.reportedDateTime && lossItem.incidentDateTime) {
    var reportedDate = toDate(lossItem.reportedDateTime);
    var incidentDate = toDate(lossItem.incidentDateTime);

    lossDays = Math.floor((reportedDate - incidentDate) / (1000 * 60 * 60 * 24));
}

// ---- Police report ----
var policeReport = false;

if (claim &&
    claim.accidentDetails &&
    claim.accidentDetails.policeReport) {

    policeReport = claim.accidentDetails.policeReport.reportRegistered === true;
}

// ---- Risk indicators ----
var riskIndicatorsSet = [];

if (lossDays > 3) {
    riskIndicatorsSet.push("LATE_REPORTED_CLAIM");
}

if (accidentCount > 3) {
    riskIndicatorsSet.push("MULTIPLE_PRIOR_CLAIMS");
}

if (policeReport !== true) {
    riskIndicatorsSet.push("NO_POLICE_REPORT");
}

// ---- Fraud score ----
var score = 0;

// Policy tenure score
if (policyTenureMonths < 6) {
    score += 25;
} else if (policyTenureMonths <= 12) {
    score += 15;
} else {
    score += 5;
}

// Prior claims score
if (accidentCount >= 5) {
    score += 30;
} else if (accidentCount >= 3) {
    score += 20;
} else if (accidentCount >= 1) {
    score += 10;
}

// Risk indicator score
for (var j = 0; j < riskIndicatorsSet.length; j++) {
    switch (riskIndicatorsSet[j]) {
        case "LATE_REPORTED_CLAIM":
            score += 15;
            break;
        case "MULTIPLE_PRIOR_CLAIMS":
            score += 20;
            break;
        case "NO_POLICE_REPORT":
            score += 10;
            break;
    }
}

// ---- Cap at 100 ----
var fraudScoreDetail = score > 100 ? 100 : score;

// ---- Risk level ----
var fraudRiskLevel = "LOW";

if (fraudScoreDetail >= 71) {
    fraudRiskLevel = "HIGH";
} else if (fraudScoreDetail >= 31) {
    fraudRiskLevel = "MEDIUM";
}

// ---- Recommendation ----
var recommendation = "PROCEED";

if (fraudRiskLevel === "MEDIUM") {
    recommendation = "HOLD / MANUAL_REVIEW";
} else if (fraudRiskLevel === "HIGH") {
    recommendation = "REFER_TO_SIU";
}

// ---- Final Output ----
var result = {
    fraudScore: fraudScoreDetail,
    riskReasons: riskIndicatorsSet.map(function(indicator) {
        switch (indicator) {
            case "LATE_REPORTED_CLAIM":
                return "Late claim reporting";
            case "MULTIPLE_PRIOR_CLAIMS":
                return "Multiple prior claims in short duration";
            case "NO_POLICE_REPORT":
                return "No police report for accident";
            default:
                return "Other risk indicator";
        }
    }),
    riskLevel: fraudRiskLevel,
    recommendation: recommendation,
    fraudRequestedDate: claim
        ? claim.claimReportedDate
        : null
};

// ---- Set final payload ----
mc.setPayloadJSON(result);
